package org.apache.commons.codec.language.bm.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.codec.language.bm.NameType;
import org.apache.commons.codec.language.bm.RuleType;
import org.apache.commons.codec.language.bm.PhoneticEngine;
import static org.junit.Assert.*;

public class StepDefs {
    private PhoneticEngine engine;
    private String input;
    private String result;

    @Given("I have a PhoneticEngine with NameType {string}, RuleType {string} and concat {string}")
    public void i_have_a_PhoneticEngine_with_NameType_RuleType_and_concat(String nameType, String ruleType, String concat) {
        NameType nType = NameType.valueOf(nameType);
        RuleType rType = RuleType.valueOf(ruleType);
        boolean c = Boolean.parseBoolean(concat);

        this.engine = new PhoneticEngine(nType, rType, c);
    }

    @When("I encode the string {string}")
    public void i_encode_the_string(String input) {
        this.input = input;
        try {
            this.result = engine.encode(input);
        } catch (Exception e) {
            // Handle any exceptions during encoding
            this.result = "ERROR: " + e.getMessage();
        }
    }

    @Then("the result should be {string}")
    public void the_result_should_be(String expected) {
        assertEquals("Encoding result does not match expected value", expected, result);
    }
}

